#import "ServiceViewController.h"
#import "ShowHeaderView.h"
#import "SendView.h"
#import "ServiceMsgModel.h"
#import "ServiceMsgCell.h"

@interface ServiceViewController ()<UITableViewDelegate, UITableViewDataSource, UITextFieldDelegate>

@property(nonatomic, strong) ShowHeaderView *headerView;
@property(strong, nonatomic) UITableView *chatTableView;
@property(strong, nonatomic) NSMutableArray<ServiceMsgModel *> *messages;
@property(nonatomic, strong) SendView *sendView;

@end

@implementation ServiceViewController

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (void)viewDidLoad {
    [super viewDidLoad];
    self.messages = [NSMutableArray array];
    if ([ServiceMsgModel allMsgs].count == 0) {
        NSString *welcome = @"Hello, I'm your dedicated support agent. Feel free to ask me any questions and I'll do my best to help.";
        CGFloat cellHeight = [self getStringWidthToCellHeight:welcome];
        ServiceMsgModel *welcomeMsg = [[ServiceMsgModel alloc] initWithContent:welcome type:MessageTypeService cellHeight:cellHeight];
        [ServiceMsgModel addMsg:welcomeMsg];
    }
    [self setUpUI];
    [_headerView showAppearAnimation];
    UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(handleTap)];
    tapGesture.cancelsTouchesInView = NO; // 不取消其他触摸事件
    [self.view addGestureRecognizer:tapGesture];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillShow:) name:UIKeyboardWillShowNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillHide:) name:UIKeyboardWillHideNotification object:nil];
}

-(void)setUpUI {

    [self.view addSubview:self.headerView];
    [self.view addSubview:self.chatTableView];
    [self.view addSubview:self.sendView];
    [_headerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view);
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(86));
    }];
    [_chatTableView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.headerView.mas_bottom);
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.sendView.mas_top);
    }];
    [_sendView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.height.mas_equalTo(ZOOMW(88));
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.view);
    }];
}

- (void)handleTap {
    [self.view endEditing:YES];
}

- (NSInteger)getStringWidthToCellHeight:(NSString *)string {
    // 将文本分割为行
    NSArray *lines = [string componentsSeparatedByString:@"\n"];

    // 计算空行数
    NSPredicate *isEmptyLinePredicate = [NSPredicate predicateWithBlock:^BOOL(id _Nullable evaluatedObject, NSDictionary * _Nullable bindings) {
        return ([evaluatedObject isKindOfClass:[NSString class]] && [(NSString *)evaluatedObject length] == 0);
    }];
    NSArray *emptyLines = [lines filteredArrayUsingPredicate:isEmptyLinePredicate];
    NSInteger emptyLineCount = (NSInteger)emptyLines.count;

    // 使用系统字体进行计算
    UIFont *font = [UIFont systemFontOfSize:16.0];

    // 计算实际文本的行数
    CGFloat totalTextHeight = 0.0;
    for (NSString *line in lines) {
        if (![emptyLines containsObject:line]) { // 只处理非空行
            // 使用boundingRect来计算文本占用的实际高度
            CGSize maxSize = CGSizeMake(ZOOMW(260), CGFLOAT_MAX);  // 最大宽度

            CGRect textRect = [line boundingRectWithSize:maxSize
                                                 options:NSStringDrawingUsesLineFragmentOrigin
                                              attributes:@{NSFontAttributeName: font}
                                                 context:nil];
            // 每一行的高度由文本占用的高度决定
            totalTextHeight += textRect.size.height;
        }
    }

    // 计算 cell 的总高度
    CGFloat cellHeight = totalTextHeight              // 计算所有文本行的总高度
    + emptyLineCount * ZOOM(19)  // 计算空行的高度，这里空行的计算是不准确的，但是在代码里进行了去空行的操作
    + ZOOM(40);                  // 添加气泡上下的间距（已涵盖所有间距）
    NSLog(@"cellHeight:%lf",cellHeight-ZOOM(40));
    return cellHeight;
}

- (void)scrollToBottom {
    if (self.messages.count > 0) {
        NSIndexPath *indexPath = [NSIndexPath indexPathForRow:self.messages.count - 1 inSection:0];
        dispatch_async(dispatch_get_main_queue(), ^{
            [self.chatTableView scrollToRowAtIndexPath:indexPath atScrollPosition:UITableViewScrollPositionBottom animated:YES];
        });
    }
}

- (void)send:(UIButton *)sender {

    NSString *userText = self.sendView.sendTextField.text;
    if (userText.length == 0) return;

    CGFloat cellHeight = [self getStringWidthToCellHeight:userText];
    [ServiceMsgModel addMsg:[[ServiceMsgModel alloc] initWithContent:userText type:MessageTypeUser cellHeight:cellHeight]];
    self.sendView.sendTextField.text = @"";
    [self.chatTableView reloadData];
    [self scrollToBottom];

    // 延迟 0.5 秒执行自动回复
    dispatch_time_t popTime = dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC));
    dispatch_after(popTime, dispatch_get_main_queue(), ^{
        NSString *answer = @"Thank you for your feedback. We're currently looking into this and will get back to you as soon as possible.";
        CGFloat cellHeight1 = [self getStringWidthToCellHeight:answer];
        [ServiceMsgModel addMsg:[[ServiceMsgModel alloc] initWithContent:answer type:MessageTypeService cellHeight:cellHeight1]];
        [self.chatTableView reloadData];
        [self scrollToBottom];
    });
}

#pragma mark - UITableViewDataSource

- (NSInteger)tableView:(UITableView *)tableView numberOfRowsInSection:(NSInteger)section {
    // 返回消息的数量
    return [ServiceMsgModel allMsgs].count;
}

- (UITableViewCell *)tableView:(UITableView *)tableView cellForRowAtIndexPath:(NSIndexPath *)indexPath {
    ServiceMsgCell *cell = [tableView dequeueReusableCellWithIdentifier:@"Cell" forIndexPath:indexPath];
    ServiceMsgModel *msg = [ServiceMsgModel allMsgs][indexPath.row];

    UIImage *userImage = [UIImage imageNamed:@"A_user"];
    UIImage *serviceImage = [UIImage imageNamed:@"A_service"];
    [cell configureWithMessage:msg iconSendImage:userImage iconReceiveImage:serviceImage];

    return cell;
}

#pragma mark - UITableViewDelegate

- (CGFloat)tableView:(UITableView *)tableView heightForRowAtIndexPath:(NSIndexPath *)indexPath {
    ServiceMsgModel *message = [ServiceMsgModel allMsgs][indexPath.row];
    return message.cellHeight > 0 ? message.cellHeight : 60.0;
}


#pragma mark - 键盘事件处理
- (BOOL)textFieldShouldReturn:(UITextField *)textField {
    if (textField == self.sendView.sendTextField) {
        [textField resignFirstResponder];
    }
    return YES;
}
- (void)keyboardWillShow:(NSNotification *)notification {
    // 获取键盘的高度
    CGSize keyboardSize = [[[notification userInfo] objectForKey:UIKeyboardFrameEndUserInfoKey] CGRectValue].size;
    // 调整消息输入框的位置
    [_sendView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.bottom.equalTo(self.view).offset(-keyboardSize.height + ZOOMW(33));
    }];
}
- (void)keyboardWillHide:(NSNotification *)notification {

    [_sendView mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.height.mas_equalTo(ZOOMW(88));
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.view);
    }];
    [self.view layoutIfNeeded]; // 强制立即更新布局
}

#pragma mark - lazy

-(ShowHeaderView *)headerView {
    if (_headerView == nil) {
        _headerView = [[ShowHeaderView alloc] init];
        _headerView.titleLabel.text = @"Support";
        _headerView.editButton.hidden = YES;
    }
    return _headerView;
}

- (UITableView *)chatTableView {
    if (_chatTableView == nil) {
        _chatTableView = [[UITableView alloc] init];
        _chatTableView.backgroundColor = BACKGROUND_COLOR;
        _chatTableView.separatorStyle = UITableViewCellSeparatorStyleNone;
        _chatTableView.showsVerticalScrollIndicator = NO;
        [self.chatTableView registerClass:[ServiceMsgCell class] forCellReuseIdentifier:@"Cell"];
        self.chatTableView.delegate = self;
        self.chatTableView.dataSource = self;
    }
    return _chatTableView;
}

- (SendView *)sendView {
    if (_sendView == nil) {
        _sendView = [[SendView alloc] init];
        [_sendView.sendButton addTarget:self action:@selector(send:) forControlEvents:UIControlEventTouchUpInside];
    }
    return _sendView;
}


@end

