    self.messages = [NSMutableArray array];
    if ([ServiceMsgModel allMsgs].count == 0) {
        NSString *welcome = @"Hello, I'm your dedicated support agent. Feel free to ask me any questions and I'll do my best to help.";
        CGFloat cellHeight = [self getStringWidthToCellHeight:welcome];
        ServiceMsgModel *welcomeMsg = [[ServiceMsgModel alloc] initWithContent:welcome type:MessageTypeService cellHeight:cellHeight];
