    [_modeview.jingmibotton addTarget:self action:@selector(togglePlayPause) forControlEvents:UIControlEventTouchUpInside];
    [_modeview.caoyuanbotton addTarget:self action:@selector(togglePlayPause) forControlEvents:UIControlEventTouchUpInside];

    // 点击"切换"按钮
    [_nextButton addTarget:self action:@selector(playNextMode) forControlEvents:UIControlEventTouchUpInside];

    [self addPlayerObserver];
}

- (void)addPlayerObserver {
    // 每隔0.1秒观察一次播放状态
    __weak typeof(self) weakSelf = self;
    [self.player addPeriodicTimeObserverForInterval:CMTimeMake(1, 10) queue:dispatch_get_main_queue() usingBlock:^(CMTime time) {
        if (weakSelf.player.rate != 0 && weakSelf.player.error == nil) {
            [weakSelf updateButtonPlayState:YES];
        } else {
            [weakSelf updateButtonPlayState:NO];
        }
    }];
}

- (void)togglePlayPause {
    if (self.player == nil || self.player.rate == 0.0) {
        // 确保有有效的播放资源
        if (_modeview.mode) {
            NSURL *url = [[NSBundle mainBundle] URLForResource:_modeview.mode withExtension:nil];
            if (url) {
                // 创建新的player实例
                self.player = [AVPlayer playerWithPlayerItem:[AVPlayerItem playerItemWithURL:url]];
                [self addPlayerObserver]; // 添加观察者

                // 请求权限以在后台播放音频，并允许与其它应用音频混合
                static dispatch_once_t onceToken;
                dispatch_once(&onceToken, ^{
                    AVAudioSession *audioSession = [AVAudioSession sharedInstance];
                    [audioSession setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:nil];
                    [audioSession setActive:YES error:nil];
                });
                [self.player play];

                [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(runLoopTheMovie:) name:AVPlayerItemDidPlayToEndTimeNotification object:_player.currentItem];
            }
        }
    } else {
        // 暂停播放
        [self.player pause];
    }
}

- (void)playNextMode {
    // 停止当前播放
    [self.player pause];

    // 更新当前索引
    _currentModeIndex++;
    if (_currentModeIndex >= kPlayModes.count) {
        _currentModeIndex = 0;
    }

    // 获取下一个模式
    NSDictionary *mode = kPlayModes[_currentModeIndex];
    NSString *buttonName = mode[@"button"];

    // 手动触发按钮的选中状态
    [self selectModeButton:buttonName];

    // 播放对应的声音
    NSURL *url = [[NSBundle mainBundle] URLForResource:mode[@"file"] withExtension:nil];
    self.player = [AVPlayer playerWithPlayerItem:[AVPlayerItem playerItemWithURL:url]];
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        AVAudioSession *audioSession = [AVAudioSession sharedInstance];
        [audioSession setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:nil];
        [audioSession setActive:YES error:nil];
    });
    [self addPlayerObserver]; // 添加观察者
    [self.player play];
}

- (void)selectModeButton:(NSString *)buttonName {
    // 重置所有按钮状态
    self.modeview.xueshanbotton.selected = NO;
    self.modeview.jingmibotton.selected = NO;
    self.modeview.caoyuanbotton.selected = NO;
    self.modeview.tianjianbotton.selected = NO;

    // 设置新选中按钮
    UIButton *selectedButton = [self.modeview valueForKey:buttonName];
    selectedButton.selected = YES;

    // 更新ModeView的mode属性
    self.modeview.mode = [kPlayModes[_currentModeIndex][@"file"] copy];

    // 触发ModeView的UI更新
    [self.modeview modeShouldUpdate:selectedButton];

    // 按钮现在在卡片容器内，用卡片容器的中心来滚动
    CGFloat cardCenterX = selectedButton.superview.center.x;
    CGFloat scrollViewWidth = self.modeview.bounds.size.width;

    // 计算需要滚动的偏移量，使卡片居中
    CGFloat offsetX = cardCenterX - scrollViewWidth / 2;

    // 确保偏移量在有效范围内
    offsetX = MAX(0, MIN(offsetX, self.modeview.contentSize.width - scrollViewWidth));

    // 执行滚动动画
    [self.modeview setContentOffset:CGPointMake(offsetX, 0) animated:YES];
}


