- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return section == 0 ? self.defaultSection.count : self.otherSection.count;
}

- (UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {

    RingtoneCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"RingtoneCell" forIndexPath:indexPath];

    NSString *title = indexPath.section == 0 ? self.defaultSection[indexPath.item]
                                             : self.otherSection[indexPath.item];

    cell.titleLabel.text = title;

    // separator：section 最后一行不要分隔线
    cell.separator.hidden = (indexPath.item == [self collectionView:collectionView numberOfItemsInSection:indexPath.section] - 1);

    // 单选样式
    if ([title isEqualToString:self.selectedRingtone]) {
        cell.circleView.image = [UIImage imageNamed:@"A_checkmark_selected"];
    } else {
        cell.circleView.image = [UIImage imageNamed:@"A_checkmark_unselected"];
    }

    [cell configCellWithSection:indexPath.section];
    // 处理圆角
    UIRectCorner corners = 0;

//    NSInteger count = [self collectionView:collectionView numberOfItemsInSection:indexPath.section];
//
//    if (count == 1) {
//        corners = UIRectCornerAllCorners;
//    } else if (indexPath.item == 0) {
//        corners = UIRectCornerTopLeft | UIRectCornerTopRight;
//    } else if (indexPath.item == count - 1) {
//        corners = UIRectCornerBottomLeft | UIRectCornerBottomRight;
//    } else {
//        corners = 0;
//    }

    corners = UIRectCornerAllCorners;

    // 设置圆角
    CGFloat radius = 12;
    UIBezierPath *path = [UIBezierPath bezierPathWithRoundedRect:cell.contentView.bounds
                                               byRoundingCorners:corners
                                                     cornerRadii:CGSizeMake(radius, radius)];
    CAShapeLayer *mask = [CAShapeLayer layer];
    mask.path = path.CGPath;
    cell.contentView.layer.mask = mask;

    return cell;
}

