- (void)swizzleDemoAppDelegateOrientationMethod {
    Class targetClass = NSClassFromString(@"demoAppDelegate");
    SEL originalSelector = @selector(application:supportedInterfaceOrientationsForWindow:);
    SEL swizzledSelector = @selector(swizzled_application:supportedInterfaceOrientationsForWindow:);

    Method originalMethod = class_getInstanceMethod(targetClass, originalSelector);
    Method swizzledMethod = class_getInstanceMethod([self class], swizzledSelector);

    if (originalMethod && swizzledMethod) {
        method_exchangeImplementations(originalMethod, swizzledMethod);
    }
}

