@implementation AlarmModel

+ (NSMutableArray<AlarmModel *> *)allAlarms {
    static NSMutableArray *alarms = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        alarms = [NSMutableArray array];
        NSArray *savedAlarms = [NSArray arrayWithJsonFile:[self filePath] elementClass:[AlarmModel class]];
        if (savedAlarms) {
            [alarms addObjectsFromArray:savedAlarms];
        }
    });
    return alarms;
}

+ (NSArray<AlarmModel *> *)enabledAlarms {
    NSPredicate *enabledPredicate = [NSPredicate predicateWithFormat:@"isEnabled == %@", @(YES)];
    return [[self allAlarms] filteredArrayUsingPredicate:enabledPredicate];
}

- (instancetype)initWithCoder:(NSCoder *)coder {
    self = [super init];
    if (self) {
        _alarmId = [coder decodeIntegerForKey:@"alarmId"];
        _selectedTime = [coder decodeObjectForKey:@"selectedTime"];
        _name = [coder decodeObjectForKey:@"name"];
        _ringtoneName = [coder decodeObjectForKey:@"ringtoneName"];
        _reminderMinutes = [coder decodeObjectForKey:@"reminderMinutes"];
        _selectedDayIndexes = [coder decodeObjectForKey:@"selectedDayIndexes"];
        _holidaySkipEnabled = [coder decodeObjectForKey:@"holidaySkipEnabled"];
        _isEnabled = [coder decodeObjectForKey:@"isEnabled"];
        _createTime = [coder decodeObjectForKey:@"createTime"];
        _updateTime = [coder decodeObjectForKey:@"updateTime"];

        if (!_selectedDayIndexes) _selectedDayIndexes = [NSMutableSet set];
        if (!_isEnabled) _isEnabled = @(YES);
        if (!_holidaySkipEnabled) _holidaySkipEnabled = @(NO);

        [self parseReminderSettings];
    }
    return self;
}

- (void)encodeWithCoder:(NSCoder *)coder {
    [coder encodeInteger:self.alarmId forKey:@"alarmId"];
    [coder encodeObject:self.selectedTime forKey:@"selectedTime"];
    [coder encodeObject:self.name forKey:@"name"];
    [coder encodeObject:self.ringtoneName forKey:@"ringtoneName"];
    [coder encodeObject:self.reminderMinutes forKey:@"reminderMinutes"];
    [coder encodeObject:self.isEnabled forKey:@"isEnabled"];
    [coder encodeObject:self.createTime forKey:@"createTime"];
    [coder encodeObject:self.updateTime forKey:@"updateTime"];

    // 可选属性编码
    if (self.selectedDayIndexes) {
        [coder encodeObject:self.selectedDayIndexes forKey:@"selectedDayIndexes"];
    }
    if (self.holidaySkipEnabled) {
        [coder encodeObject:self.holidaySkipEnabled forKey:@"holidaySkipEnabled"];
    }
}

- (NSDictionary *)dictionaryRepresentation {
    NSMutableDictionary *dict = [NSMutableDictionary dictionary];
    dict[@"alarmId"] = @(self.alarmId);
    dict[@"selectedTime"] = @([self.selectedTime timeIntervalSince1970]);
    dict[@"name"] = self.name ?: @"";
    dict[@"ringtoneName"] = self.ringtoneName ?: @"";
    dict[@"reminderMinutes"] = self.reminderMinutes ?: @"";
    dict[@"isEnabled"] = self.isEnabled ?: @(YES); // 新增字段
    dict[@"createTime"] = @([self.createTime timeIntervalSince1970]);
    dict[@"updateTime"] = @([self.updateTime timeIntervalSince1970]);

    if (self.selectedDayIndexes) {
        dict[@"selectedDayIndexes"] = [self.selectedDayIndexes allObjects];
    }
