#import "AlarmManager.h"


@implementation AlarmManager

+ (NSString *)soundFileNameForDisplayName:(NSString *)displayName {
    if (displayName.length == 0) {
        return @"Default ringtone.mp3";
    }

    NSDictionary<NSString *, NSString *> *soundMap = @{
        @"默认铃声": @"Default ringtone.mp3",
        @"经典": @"Classic ringtone.mp3",
        @"天气": @"Weather ringtone.mp3",
        @"自然": @"Natural ringtone.mp3",
    };

    NSString *mappedName = soundMap[displayName];
    if (mappedName.length > 0) {
        return mappedName;
    }

    if ([[displayName.pathExtension lowercaseString] isEqualToString:@"mp3"]) {
        return displayName;
    }

    return @"Default ringtone.mp3";
}

