#pragma mark - Private Helpers

/**
 安全取值：将 nil/NSNull 视为 nil
 */
 - (id)safeValueForKey:(NSString *)key fromDictionary:(NSDictionary *)dict {
    id value = [dict objectForKey:key];
    if (value == [NSNull null] || value == nil) {
        return nil;
    }
    return value;
}

/**
 统一处理反馈接口的原始 JSON
 - 校验响应结构与状态码
 - 失败返回中文错误
 - 成功映射为 FeedbackModel 数组
 */
 - (void)processFeedbackJSON:(id)json error:(NSError *)error completion:(WBFeedbackListCallback)completion {
    if (error) {
        if (completion) {
            NSError *cnError = [NSError errorWithDomain:@"FeedbackManager" code:error.code userInfo:@{NSLocalizedDescriptionKey: [NSString stringWithFormat:@"请求出现错误：%@", error.localizedDescription ?: @"未知错误"]}];
            completion(nil, cnError);
        }
        return;
    }
    if (!json || json == [NSNull null] || ![json isKindOfClass:[NSDictionary class]]) {
        if (completion) {
            NSError *respErr = [NSError errorWithDomain:@"FeedbackManager" code:-1 userInfo:@{NSLocalizedDescriptionKey: @"响应数据无效"}];
            completion(nil, respErr);
        }
        return;
    }
    NSDictionary *dict = (NSDictionary *)json;
    NSNumber *code = dict[@"code"];
    NSString *message = dict[@"message"];
    if ((code && [code integerValue] == 200 && [message isKindOfClass:NSString.class] && [message isEqualToString:@"success"])) {
        NSDictionary *data = [self safeValueForKey:@"data" fromDictionary:dict];
        NSArray<FeedbackModel *> *result = [self mapFeedbackListFromData:data];
        if (completion) {
            completion(result ?: @[], nil);
        }
    } else {
        if (completion) {
            NSInteger ec = [code isKindOfClass:NSNumber.class] ? [code integerValue] : -2;
            NSString *desc = ([message isKindOfClass:NSString.class] && [(NSString *)message length] > 0) ? [NSString stringWithFormat:@"请求失败：%@", (NSString *)message] : @"请求失败";
            NSError *respErr = [NSError errorWithDomain:@"FeedbackManager" code:ec userInfo:@{NSLocalizedDescriptionKey: desc}];
            completion(nil, respErr);
        }
    }
}

/**
 将 data.list 映射为 FeedbackModel 数组
 */
 - (NSArray<FeedbackModel *> *)mapFeedbackListFromData:(NSDictionary *)data {
    id listRaw = [self safeValueForKey:@"list" fromDictionary:data];
    NSArray *list = [listRaw isKindOfClass:NSArray.class] ? (NSArray *)listRaw : nil;
    NSMutableArray<FeedbackModel *> *result = [NSMutableArray arrayWithCapacity:list.count];
    if (list) {
        for (id item in list) {
            NSDictionary *m = [item isKindOfClass:NSDictionary.class] ? (NSDictionary *)item : nil;
            if (!m) { continue; }
            FeedbackModel *model = [self modelFromDict:m];
            if (model) {
                [result addObject:model];
            }
        }
    }
    return result;
}

/**
 单条反馈字典 -> FeedbackModel
 - 兼容类型：id/admin 支持 NSString/NSNumber
 - 时间：保留后端字符串 created_at
 - 类型映射：text/image -> 枚举
 */
- (FeedbackModel *)modelFromDict:(NSDictionary *)m {
    FeedbackModel *model = [FeedbackModel new];
    id textRaw = [self safeValueForKey:@"text" fromDictionary:m];
    id adminRaw = [self safeValueForKey:@"admin" fromDictionary:m];
    id createdRaw = [self safeValueForKey:@"created_at" fromDictionary:m];
    id msgIdRaw = [self safeValueForKey:@"id" fromDictionary:m];
    id msgTypeRaw = [self safeValueForKey:@"type" fromDictionary:m];
    id imageRaw = [self safeValueForKey:@"image" fromDictionary:m];

    NSString *text = [textRaw isKindOfClass:NSString.class] ? (NSString *)textRaw : @"";
    NSInteger adminVal = 0;
    if ([adminRaw isKindOfClass:NSNumber.class]) { adminVal = [(NSNumber *)adminRaw integerValue]; }
    else if ([adminRaw isKindOfClass:NSString.class]) { adminVal = [(NSString *)adminRaw integerValue]; }
    NSString *created = [createdRaw isKindOfClass:NSString.class] ? (NSString *)createdRaw : @"";
    NSInteger msgId = 0;
    if ([msgIdRaw isKindOfClass:NSNumber.class]) { msgId = [(NSNumber *)msgIdRaw integerValue]; }
    else if ([msgIdRaw isKindOfClass:NSString.class]) { msgId = [(NSString *)msgIdRaw integerValue]; }
    NSString *msgType = [msgTypeRaw isKindOfClass:NSString.class] ? (NSString *)msgTypeRaw : @"";
    NSString *imageURL = [imageRaw isKindOfClass:NSString.class] ? (NSString *)imageRaw : @"";

    FeedbackType type = FeedbackTypeNone;
    if ([msgType isEqualToString:@"text"]) {
        type = FeedbackTypeText;
    } else if ([msgType isEqualToString:@"image"]) {
        type = FeedbackTypeImage;
    }

    model.content = text;
    model.imageURL = imageURL;
    model.isSend = (adminVal == 0);
    model.time = created;
    model.msgId = msgId;
    model.type = type;
    return model;
}


